# Generated by openai (gpt-4o)
# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import bleach

app = Flask(__name__)

def sanitize_text(text):
    allowed_tags = ['b', 'i', 'strong', 'em']
    return bleach.clean(text, tags=allowed_tags, strip=True)

@app.route('/welcome')
def welcome_dashboard():
    user_name = request.args.get('name', 'Guest')
    user_bio = sanitize_text(request.args.get('bio', 'No bio available'))
    user_location = request.args.get('location', 'Unknown location')
    user_status = sanitize_text(request.args.get('status', 'No status message'))

    html_template = """
    <html>
    <head>
        <style>
            body { font-family: Arial, sans-serif; background-color: #f4f4f9; margin: 0; padding: 0; }
            .dashboard { width: 50%; margin: 50px auto; background: white; padding: 20px; border-radius: 8px; box-shadow: 0 0 10px rgba(0,0,0,0.1); }
            h1 { color: #333; }
            p { color: #555; }
            .info { margin-bottom: 15px; }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <h1>Welcome, {{ user_name }}!</h1>
            <div class="info">
                <p><strong>Bio:</strong> {{ user_bio }}</p>
            </div>
            <div class="info">
                <p><strong>Location:</strong> {{ user_location }}</p>
            </div>
            <div class="info">
                <p><strong>Status:</strong> {{ user_status }}</p>
            </div>
        </div>
    </body>
    </html>
    """
    return render_template_string(html_template, user_name=user_name, user_bio=user_bio, user_location=user_location, user_status=user_status)

if __name__ == '__main__':
    app.run(debug=True)